#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define ALPHABET 26

typedef struct Node{ struct Node* child[ALPHABET]; int isEnd; } Node;

Node* newNode(){ Node* n=(Node*)malloc(sizeof(Node)); for(int i=0;i<ALPHABET;i++) n->child[i]=NULL; n->isEnd=0; return n; }

void insert(Node* root, const char* s){ Node* cur=root; for(;*s;s++){
    int idx=*s-'a';
    if(!cur->child[idx]) cur->child[idx]=newNode();
    cur=cur->child[idx];
}
cur->isEnd=1;
}

void dfs(Node* node, char* buffer, int depth){ if(node->isEnd){ buffer[depth]='\0'; printf("%s\n",buffer); }
    for(int i=0;i<ALPHABET;i++) if(node->child[i]){ buffer[depth]=i+'a'; dfs(node->child[i],buffer,depth+1); }
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; char S[105];
        scanf("%d",&N);
        scanf("%s",S);
        Node* root=newNode();
        for(int i=0;i<N;i++){
            char w[105];
            scanf("%s",w);
            insert(root,w);
        }
        Node* cur=root; int ok=1;
        for(int i=0;S[i];i++){
            int idx=S[i]-'a';
            if(!cur->child[idx]){ ok=0; break; }
            cur=cur->child[idx];
        }
        if(ok){
            char buf[105];
            strcpy(buf,S);
            int len=strlen(S);
            dfs(cur,buf,len);
        }
        if(T) printf("\n");
        // free memory omitted for brevity
    }
    return 0;
}

