import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        Node[] child = new Node[26];
        boolean end = false;
    }
    static void insert(Node root, String s){
        Node cur = root;
        for(char c: s.toCharArray()){
            int idx = c - 'a';
            if(cur.child[idx]==null) cur.child[idx]=new Node();
            cur = cur.child[idx];
        }
        cur.end = true;
    }
    static void dfs(Node node, StringBuilder sb, BufferedWriter out) throws IOException{
        if(node.end){ out.write(sb.toString()); out.newLine(); }
        for(int i=0;i<26;i++) if(node.child[i]!=null){
            sb.append((char)('a'+i));
            dfs(node.child[i], sb, out);
            sb.deleteCharAt(sb.length()-1);
        }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        BufferedWriter out = new BufferedWriter(new OutputStreamWriter(System.out));
        int T = Integer.parseInt(br.readLine().trim());
        while(T-- > 0){
            int N = Integer.parseInt(br.readLine().trim());
            String S = br.readLine().trim();
            Node root = new Node();
            for(int i=0;i<N;i++){
                String w = br.readLine().trim();
                insert(root,w);
            }
            Node cur = root; boolean ok = true;
            for(char c: S.toCharArray()){
                int idx = c - 'a';
                if(cur.child[idx]==null){ ok = false; break; }
                cur = cur.child[idx];
            }
            if(ok){
                StringBuilder sb = new StringBuilder(S);
                dfs(cur, sb, out);
            }
            if(T>0) out.newLine(); // optional blank line between test cases
        }
        out.flush();
    }
}

