import sys

class Node:
    __slots__ = ('child','end')
    def __init__(self):
        self.child = [None]*26
        self.end = False

def insert(root, word):
    cur = root
    for ch in word:
        idx = ord(ch)-97
        if cur.child[idx] is None:
            cur.child[idx] = Node()
        cur = cur.child[idx]
    cur.end = True

def dfs(node, path, out):
    if node.end:
        out.append(''.join(path))
    for i in range(26):
        child = node.child[i]
        if child is not None:
            path.append(chr(i+97))
            dfs(child, path, out)
            path.pop()

def solve():
    data = sys.stdin.read().splitlines()
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        S = next(it).strip()
        root = Node()
        for _ in range(N):
            w = next(it).strip()
            insert(root, w)
        cur = root
        ok = True
        for ch in S:
            idx = ord(ch)-97
            if cur.child[idx] is None:
                ok = False
                break
            cur = cur.child[idx]
        if ok:
            dfs(cur, list(S), out_lines)
        if _ != T-1:
            out_lines.append('')  # optional separator (will produce a blank line)
    sys.stdout.write('\n'.join(out_lines).rstrip('\n'))

if __name__ == "__main__":
    solve()

